package main

import (
    "encoding/json"
    "fmt"
)

// ---- Struct for JSON ----
type Player struct {
    Name   string `json:"name"`
    Health int    `json:"health"`
    Attack int    `json:"attack"`
    Level  int    `json:"level"`
}

type GameState struct {
    Players []Player `json:"players"`
    Score   int      `json:"score"`
    Level   int      `json:"level"`
}

func main() {
    // ---- Marshal (encode to JSON) ----
    fmt.Println("=== Marshal ===")

    player := Player{
        Name:   "Hero",
        Health: 100,
        Attack: 20,
        Level:  5,
    }

    jsonData, err := json.Marshal(player)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Println("JSON:", string(jsonData))

    // ---- Pretty print ----
    prettyJSON, err := json.MarshalIndent(player, "", "  ")
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Println("Pretty JSON:")
    fmt.Println(string(prettyJSON))

    // ---- Unmarshal (decode from JSON) ----
    fmt.Println("\n=== Unmarshal ===")

    jsonStr := `{"name":"Aragorn","health":120,"attack":25,"level":8}`

    var newPlayer Player
    err = json.Unmarshal([]byte(jsonStr), &newPlayer)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Printf("Player: %+v\n", newPlayer)

    // ---- Marshal with map ----
    fmt.Println("\n=== Marshal with Map ===")

    m := map[string]interface{}{
        "name":   "Gandalf",
        "health": 80,
        "attack": 15,
        "level":  6,
    }

    jsonMap, err := json.Marshal(m)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Println("Map JSON:", string(jsonMap))

    // ---- Unmarshal to map ----
    fmt.Println("\n=== Unmarshal to Map ===")

    jsonStr2 := `{"name":"Legolas","health":90,"attack":22,"level":7}`

    var m2 map[string]interface{}
    err = json.Unmarshal([]byte(jsonStr2), &m2)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    for k, v := range m2 {
        fmt.Printf("%s: %v\n", k, v)
    }

    // ---- Marshal nested struct ----
    fmt.Println("\n=== Nested JSON ===")

    game := GameState{
        Players: []Player{
            {Name: "Hero", Health: 100, Attack: 20, Level: 5},
            {Name: "Aragorn", Health: 120, Attack: 25, Level: 8},
        },
        Score: 1000,
        Level: 3,
    }

    gameJSON, err := json.MarshalIndent(game, "", "  ")
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Println("Game JSON:")
    fmt.Println(string(gameJSON))
}

