package main

import (
    "encoding/json"
    "fmt"
)

type Item struct {
    Name   string `json:"name"`
    Value  int    `json:"value"`
    Weight int    `json:"weight"`
}

func main() {
    item := Item{Name: "Sword", Value: 50, Weight: 3}

    data, err := json.Marshal(item)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    fmt.Println("Marshaled:", string(data))

    jsonStr := `{"name":"Shield","value":40,"weight":5}`
    var item2 Item
    err = json.Unmarshal([]byte(jsonStr), &item2)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    fmt.Printf("Unmarshaled: %+v\n", item2)
}
